# modules/networking/vpc/main.tf
terraform {
required_version = ">= 1.5.0"
required_providers {
aws = {
source  = "hashicorp/aws"
version = "~> 5.0"
}
}
backend "s3" {
bucket         = "terraform-state-bucket"
key            = "networking/vpc"
region         = "us-east-1"
encrypt        = true
dynamodb_table = "terraform-locks"
}
}
variable "environment" {
description = "Environment name (dev, staging, prod)"
type        = string
}
variable "cidr_block" {
description = "CIDR block for VPC"
type        = string
default     = "10.0.0.0/16"
}
variable "availability_zones" {
description = "List of AZs for subnets"
type        = list(string)
default     = ["us-east-1a", "us-east-1b", "us-east-1c"]
}
variable "public_subnet_cidrs" {
description = "CIDR blocks for public subnets"
type        = list(string)
default     = ["10.0.1.0/24", "10.0.2.0/24", "10.0.3.0/24"]
}
variable "private_subnet_cidrs" {
description = "CIDR blocks for private subnets"
type        = list(string)
default     = ["10.0.11.0/24", "10.0.12.0/24", "10.0.13.0/24"]
}
variable "enable_nat_gateway" {
description = "Enable NAT Gateway for private subnets"
type        = bool
default     = true
}
variable "tags" {
description = "Common tags to apply to resources"
type        = map(string)
default     = {}
}
locals {
name_prefix = "${var.environment}-vpc"
common_tags = merge(
var.tags,
{
Environment = var.environment
ManagedBy   = "terraform"
Project     = "decapod"
}
)
}
resource "aws_vpc" "main" {
cidr_block           = var.cidr_block
enable_dns_hostnames = true
enable_dns_support   = true
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-vpc"
}
)
}
resource "aws_internet_gateway" "main" {
vpc_id = aws_vpc.main.id
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-igw"
}
)
}
resource "aws_subnet" "public" {
count             = length(var.public_subnet_cidrs)
vpc_id            = aws_vpc.main.id
cidr_block        = var.public_subnet_cidrs[count.index]
availability_zone = var.availability_zones[count.index]
map_public_ip_on_launch = true
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-public-${count.index + 1}"
Type = "public"
}
)
}
resource "aws_subnet" "private" {
count             = length(var.private_subnet_cidrs)
vpc_id            = aws_vpc.main.id
cidr_block        = var.private_subnet_cidrs[count.index]
availability_zone = var.availability_zones[count.index]
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-private-${count.index + 1}"
Type = "private"
}
)
}
resource "aws_eip" "nat" {
count  = var.enable_nat_gateway ? length(var.availability_zones) : 0
domain = "vpc"
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-nat-eip-${count.index + 1}"
}
)
depends_on = [aws_internet_gateway.main]
}
resource "aws_nat_gateway" "main" {
count         = var.enable_nat_gateway ? length(var.availability_zones) : 0
allocation_id = aws_eip.nat[count.index].id
subnet_id     = aws_subnet.public[count.index].id
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-nat-${count.index + 1}"
}
)
depends_on = [aws_internet_gateway.main]
}
resource "aws_route_table" "public" {
vpc_id = aws_vpc.main.id
route {
cidr_block = "0.0.0.0/0"
gateway_id = aws_internet_gateway.main.id
}
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-public-rt"
}
)
}
resource "aws_route_table" "private" {
count  = var.enable_nat_gateway ? length(var.availability_zones) : 0
vpc_id = aws_vpc.main.id
route {
cidr_block     = "0.0.0.0/0"
nat_gateway_id = aws_nat_gateway.main[count.index].id
}
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-private-rt-${count.index + 1}"
}
)
}
resource "aws_route_table_association" "public" {
count          = length(var.public_subnet_cidrs)
subnet_id      = aws_subnet.public[count.index].id
route_table_id = aws_route_table.public.id
}
resource "aws_route_table_association" "private" {
count          = length(var.private_subnet_cidrs)
subnet_id      = aws_subnet.private[count.index].id
route_table_id = aws_route_table.private[count.index % length(var.availability_zones)].id
}
# VPC Endpoints for private connectivity to AWS services
resource "aws_vpc_endpoint" "s3" {
vpc_id       = aws_vpc.main.id
service_name = "com.amazonaws.${var.availability_zones[0].split("-")[0]}-${var.availability_zones[0].split("-")[1]}.s3"
route_table_ids = concat(
[aws_route_table.public.id],
aws_route_table.private[*].id
)
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-s3-endpoint"
}
)
}
resource "aws_vpc_endpoint" "ecr_api" {
vpc_id       = aws_vpc.main.id
service_name = "com.amazonaws.${var.availability_zones[0].split("-")[0]}-${var.availability_zones[0].split("-")[1]}.ecr.api"
vpc_endpoint_type = "Interface"
security_groups = [aws_security_group.vpc_endpoints.id]
private_dns_enabled = true
subnet_ids = aws_subnet.private[*].id
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-ecr-api-endpoint"
}
)
}
resource "aws_security_group" "vpc_endpoints" {
name        = "${local.name_prefix}-vpc-endpoints"
description = "Security group for VPC endpoints"
vpc_id      = aws_vpc.main.id
tags = merge(
local.common_tags,
{
Name = "${local.name_prefix}-vpc-endpoints-sg"
}
)
}
resource "aws_security_group_rule" "vpc_endpoints_ingress" {
type              = "ingress"
from_port         = 443
to_port           = 443
protocol          = "tcp"
cidr_blocks       = [var.cidr_block]
security_group_id = aws_security_group.vpc_endpoints.id
description       = "Allow HTTPS from VPC"
}
output "vpc_id" {
description = "ID of the created VPC"
value       = aws_vpc.main.id
}
output "vpc_cidr" {
description = "CIDR block of the VPC"
value       = aws_vpc.main.cidr_block
}
output "public_subnet_ids" {
description = "IDs of public subnets"
value       = aws_subnet.public[*].id
}
output "private_subnet_ids" {
description = "IDs of private subnets"
value       = aws_subnet.private[*].id
}
output "nat_gateway_ips" {
description = "IP addresses of NAT Gateways"
value       = var.enable_nat_gateway ? aws_eip.nat[*].public_ip : []
}

