// profiling/setup.js - Node.js profiling
const { PerformanceObserver, performance } = require('perf_hooks');
const v8 = require('v8');
const fs = require('fs');
const path = require('path');
class ProfilerManager {
constructor(options = {}) {
this.outputDir = options.outputDir || '/tmp/profiles';
this.enabled = false;
// Ensure output directory exists
if (!fs.existsSync(this.outputDir)) {
fs.mkdirSync(this.outputDir, { recursive: true });
}
}
startCPUProfile(name) {
if (this.enabled) return;
this.enabled = true;
v8.startSampling();
// Schedule profile dump
this.cpuProfileName = name;
this.cpuProfileStart = Date.now();
}
stopCPUProfile(name) {
if (!this.enabled) return;
v8.stopSampling();
this.enabled = false;
const filename = path.join(
this.outputDir,
`${name}-${Date.now()}.cpuprofile`
);
const profile = v8.stopSampling();
fs.writeFileSync(filename, JSON.stringify(profile));
console.log(`CPU profile saved to: ${filename}`);
}
startMemoryTracking() {
// Enable memory profiling
if (global.gc) {
global.gc(); // Run GC before starting
}
this.memorySnapshots = [];
this.memoryInterval = setInterval(() => {
if (global.gc) {
global.gc();
}
const heapStats = v8.getHeapStatistics();
this.memorySnapshots.push({
timestamp: Date.now(),
heapUsed: heapStats.used_heap_size,
heapTotal: heapStats.total_heap_size,
heapLimit: heapStats.heap_size_limit,
});
}, 5000);
}
stopMemoryTracking() {
if (this.memoryInterval) {
clearInterval(this.memoryInterval);
this.memoryInterval = null;
}
return this.memorySnapshots;
}
takeHeapSnapshot(name) {
const filename = path.join(
this.outputDir,
`${name}-${Date.now()}.heapsnapshot`
);
const snapshot = v8.writeHeapSnapshot(filename);
console.log(`Heap snapshot saved to: ${snapshot}`);
return snapshot;
}
getHeapStatistics() {
return v8.getHeapStatistics();
}
getSpaceStatistics() {
return v8.getHeapSpaceStatistics();
}
}
// Performance hooks for custom metrics
function setupPerformanceObservers() {
const obs = new PerformanceObserver((items) => {
items.getEntries().forEach(entry => {
console.log('Performance entry:', {
name: entry.name,
duration: entry.duration,
entryType: entry.entryType,
});
});
});
// Observe all performance events
obs.observe({ entryTypes: ['measure', 'mark', 'navigation', 'resource'] });
}
// Custom timing helper
function measure(name, fn) {
return async (...args) => {
performance.mark(`${name}-start`);
try {
const result = await fn(...args);
performance.mark(`${name}-end`);
performance.measure(name, `${name}-start`, `${name}-end`);
return result;
} catch (error) {
performance.mark(`${name}-error`);
throw error;
}
};
}
// HTTP request timing middleware
function requestTimingMiddleware(req, res, next) {
const start = process.hrtime.bigint();
res.on('finish', () => {
const end = process.hrtime.bigint();
const durationMs = Number(end - start) / 1_000_000;
console.log({
method: req.method,
url: req.url,
status: res.statusCode,
duration: `${durationMs.toFixed(2)}ms`,
});
});
next();
}
module.exports = {
ProfilerManager,
setupPerformanceObservers,
measure,
requestTimingMiddleware,
};

sections.2.1 Go Memory Management:
// memory/management.go - Go memory optimization patterns
package memory
import (
"runtime"
"runtime/debug"
"sync"
"time"
"unsafe"
)
// Object pool for reducing allocations
type ObjectPool[T any] struct {
pool sync.Pool
new  func() *T
}
func NewObjectPool[T any](factory func() *T) *ObjectPool[T] {
return &ObjectPool[T]{
pool: sync.Pool{
New: func() interface{} {
return factory()
},
},
new: factory,
}
}
func (p *ObjectPool[T]) Get() *T {
if val := p.pool.Get(); val != nil {
return val.(*T)
}
return p.new()
}
func (p *ObjectPool[T]) Put(obj *T) {
p.pool.Put(obj)
}
// Buffer pool for I/O operations
type BufferPool struct {
sizes     []int
pools     []*sync.Pool
maxSize   int
}
func NewBufferPool(minSize, maxSize int, factor float64) *BufferPool {
var sizes []int
size := minSize
for size < maxSize {
sizes = append(sizes, size)
size = int(float64(size) * factor)
}
pools := make([]*sync.Pool, len(sizes))
for i, s := range sizes {
sz := s
pools[i] = &sync.Pool{
New: func() interface{} {
return make([]byte, sz)
},
}
}
return &BufferPool{
sizes:   sizes,
pools:   pools,
maxSize: maxSize,
}
}
func (p *BufferPool) Get(size int) []byte {
for i, s := range p.sizes {
if size <= s {
return p.pools[i].Get().([]byte)[:size]
}
}
return make([]byte, size)
}
func (p *BufferPool) Put(buf []byte) {
for i, s := range p.sizes {
if cap(buf) == s {
p.pools[i].Put(buf[:cap(buf)])
return
}
}
}
// Memory profiler with metrics
type MemoryProfiler struct {
interval time.Duration
stop     chan struct{}
history  []MemorySnapshot
}
type MemorySnapshot struct {
Timestamp  time.Time
HeapAlloc  uint64
HeapSys    uint64
StackInuse uint64
GCNum      uint32
GCLatest   time.Time
}
func (m *MemoryProfiler) Start(interval time.Duration) {
m.interval = interval
m.stop = make(chan struct{})
go m.collect()
}
func (m *MemoryProfiler) Stop() {
if m.stop != nil {
close(m.stop)
}
}
func (m *MemoryProfiler) collect() {
tick := time.NewTicker(m.interval)
defer tick.Stop()
for {
select {
case <-tick.C:
m.record()
case <-m.stop:
return
}
}
}
func (m *MemoryProfiler) record() {
var ms runtime.MemStats
runtime.ReadMemStats(&ms)
snapshot := MemorySnapshot{
Timestamp:  time.Now(),
HeapAlloc:   ms.HeapAlloc,
HeapSys:     ms.HeapSys,
StackInuse:  ms.StackInuse,
GCNum:       ms.NumGC,
GCLatest:    time.Unix(0, int64(ms.LastGC)),
}
m.history = append(m.history, snapshot)
// Keep only last 1000 snapshots
if len(m.history) > 1000 {
m.history = m.history[len(m.history)-1000:]
}
}
// GOGC tuning
func SetGOGC(percent int) {
debug.SetGCPercent(percent)
}
func GetGOGC() int {
return debug.ReadGCPercent()
}
// Preallocate slices for known capacity
func PreallocateSlice(size int) []byte {
return make([]byte, 0, size)
}
// StringBuilder for string concatenation
func EfficientConcat(parts []string) string {
var sb strings.Builder
sb.Grow(len(parts) * 10) // Estimate size
for _, part := range parts {
sb.WriteString(part)
}
return sb.String()
}
// Memory-mapped files for large data
func MemoryMapFile(filename string) ([]byte, error) {
f, err := os.Open(filename)
if err != nil {
return nil, err
}
defer f.Close()
fi, err := f.Stat()
if err != nil {
return nil, err
}
return syscall.Mmap(
int(f.Fd()),
0,
int(fi.Size()),
syscall.PROT_READ,
syscall.MAP_PRIVATE,
)
}
// Cache with eviction
type Cache[K comparable, V any] struct {
data     map[K]V
maxSize  int
mu       sync.RWMutex
onEvict  func(K, V)
}
func NewCache[K comparable, V any](maxSize int, onEvict func(K, V)) *Cache[K, V] {
return &Cache[K, V]{
data:    make(map[K]V, maxSize),
maxSize: maxSize,
onEvict: onEvict,
}
}
func (c *Cache[K, V]) Get(key K) (V, bool) {
c.mu.RLock()
defer c.mu.RUnlock()
val, ok := c.data[key]
return val, ok
}
func (c *Cache[K, V]) Set(key K, val V) {
c.mu.Lock()
defer c.mu.Unlock()
if len(c.data) >= c.maxSize {
// Evict oldest (simple FIFO, could use LRU)
for k, v := range c.data {
delete(c.data, k)
if c.onEvict != nil {
c.onEvict(k, v)
}
break
}
}
c.data[key] = val
}

