// memory/leak_prevention.go - Patterns to prevent memory leaks
package memory
import (
"context"
"runtime"
"sync"
"time"
)
// Context with cancellation to prevent goroutine leaks
func PreventGoroutineLeak() {
ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
defer cancel()
done := make(chan struct{})
go func() {
// Long-running operation
// Will be cancelled after 5 seconds
select {
case <-ctx.Done():
// Clean up
case <-done:
// Normal completion
}
}()
}
// WaitGroup for tracking goroutine completion
func TrackGoroutines() {
var wg sync.WaitGroup
for i := 0; i < 10; i++ {
wg.Add(1)
go func(id int) {
defer wg.Done()
// Work
}(i)
}
wg.Wait() // Block until all done
}
// Timer cleanup
func TimerCleanup() {
timer := time.NewTimer(30 * time.Second)
defer timer.Stop() // Always cleanup timers
select {
case <-timer.C:
// Handle timeout
case <-time.After(1 * time.Hour):
// This would cause a leak if timer wasn't stopped
}
}
// Resource cleanup pattern
type Resource struct {
data []byte
}
func (r *Resource) Close() error {
r.data = nil
return nil
}
func UseResources() error {
// Multi-resource cleanup
f, err := os.Create("file.txt")
if err != nil {
return err
}
// Get connection
conn, err := net.Dial("tcp", "localhost:8080")
if err != nil {
f.Close()
return err
}
// Defer cleanup (LIFO order)
defer conn.Close()
defer f.Close()
// Use resources...
return nil
}
// Channel cleanup to prevent goroutine blocks
func ChannelCleanup() {
ch := make(chan int, 100)
// Producer
go func() {
for i := 0; i < 10; i++ {
ch <- i
}
close(ch) // Always close channels
}()
// Consumer
for val := range ch {
// Process val
_ = val
}
}
// Map access pattern for concurrent access
func ConcurrentMapAccess() {
var mu sync.RWMutex
m := make(map[string]int)
// Read
mu.RLock()
val := m["key"]
mu.RUnlock()
_ = val
// Write
mu.Lock()
m["key"] = 42
mu.Unlock()
}
// Periodic cleanup for caches
func StartPeriodicCleanup(cleanupFn func(), interval time.Duration) func() {
stop := make(chan struct{})
go func() {
tick := time.NewTicker(interval)
defer tick.Stop()
for {
select {
case <-tick.C:
cleanupFn()
case <-stop:
return
}
}
}()
return func() {
close(stop)
}
}

sections.3.1 Goroutine Optimization:
// cpu/goroutine_optimization.go
package cpu
import (
"runtime"
"sync"
"sync/atomic"
)
// Worker pool with bounded concurrency
type WorkerPool struct {
work    chan func() error
results chan error
wg      sync.WaitGroup
}
func NewWorkerPool(workers, queueSize int) *WorkerPool {
pool := &WorkerPool{
work:    make(chan func() error, queueSize),
results: make(chan error, queueSize),
}
for i := 0; i < workers; i++ {
pool.wg.Add(1)
go pool.worker()
}
return pool
}
func (p *WorkerPool) worker() {
defer p.wg.Done()
for work := range p.work {
if err := work(); err != nil {
p.results <- err
}
}
}
func (p *WorkerPool) Submit(work func() error) {
p.work <- work
}
func (p *WorkerPool) Shutdown() {
close(p.work)
p.wg.Wait()
close(p.results)
}
// Semaphore for limiting concurrency
type Semaphore struct {
sem     chan struct{}
count   int64
maxSize int
}
func NewSemaphore(maxSize int) *Semaphore {
return &Semaphore{
sem:     make(chan struct{}, maxSize),
maxSize: maxSize,
}
}
func (s *Semaphore) Acquire() {
s.sem <- struct{}{}
atomic.AddInt64(&s.count, 1)
}
func (s *Semaphore) Release() {
<-s.sem
atomic.AddInt64(&s.count, -1)
}
func (s *Semaphore) Count() int64 {
return atomic.LoadInt64(&s.count)
}
func (s *Semaphore) TryAcquire() bool {
select {
case s.sem <- struct{}{}:
atomic.AddInt64(&s.count, 1)
return true
default:
return false
}
}
// Atomic operations for counters
type AtomicCounter struct {
count int64
}
func (c *AtomicCounter) Increment() int64 {
return atomic.AddInt64(&c.count, 1)
}
func (c *AtomicCounter) Decrement() int64 {
return atomic.AddInt64(&c.count, -1)
}
func (c *AtomicCounter) Get() int64 {
return atomic.LoadInt64(&c.count)
}
// Parallel processing with bounded memory
func ParallelProcess[T any, R any](
items []T,
fn func(T) R,
workers int,
) []R {
if len(items) == 0 {
return nil
}
results := make([]R, len(items))
// Determine chunk size
chunkSize := (len(items) + workers - 1) / workers
if chunkSize < 1 {
chunkSize = 1
}
var wg sync.WaitGroup
for i := 0; i < len(items); i += chunkSize {
wg.Add(1)
start := i
end := i + chunkSize
if end > len(items) {
end = len(items)
}
go func(start, end int) {
defer wg.Done()
for j := start; j < end; j++ {
results[j] = fn(items[j])
}
}(start, end)
}
wg.Wait()
return results
}
// Batch processing to reduce overhead
func BatchProcess[T any](
items []T,
batchSize int,
fn func([]T) error,
) error {
for i := 0; i < len(items); i += batchSize {
end := i + batchSize
if end > len(items) {
end = len(items)
}
if err := fn(items[i:end]); err != nil {
return err
}
}
return nil
}
// GOMAXPROCS configuration
func OptimizeCPU() {
// Get number of CPU cores
numCPU := runtime.NumCPU()
// Set to use all cores
runtime.GOMAXPROCS(numCPU)
// Or limit for specific workloads
// runtime.GOMAXPROCS(4)
}
// Mutex vs atomic selection guide
// Use atomic for: counters, flags, simple values
// Use mutex for: complex data structures, multiple fields
// Spinlock for short critical sections
type SpinLock struct {
locked uint32
}
func (s *SpinLock) Lock() {
for !atomic.CompareAndSwapUint32(&s.locked, 0, 1) {
runtime.Gosched() // Yield
}
}
func (s *SpinLock) Unlock() {
atomic.StoreUint32(&s.locked, 0)
}

